def _participant_error(db: Session, bill_id: str, user_id: str):
    try:
        require_bill_participant(db, bill_id, user_id)
    except ValueError as e:
        code = str(e)
        if code == "NOT_FOUND":
            return error_response("NOT_FOUND", "Bill not found", 404)
        return error_response("FORBIDDEN", "Not authorized", 403)
    return None

