def _schedule_payment_sms(bill_id: str, owner_id: str) -> None:
    db = SessionLocal()
    try:
        PaymentNotificationService(db).sync_request_sms_for_bill(bill_id, owner_id)
    except Exception:
        logger.exception("Payment notification SMS failed for bill %s", bill_id)
    finally:
        db.close()

app/api/routes/assignments.py :: _broadcast_delta
def _broadcast_delta(
    bill_id: str,
    action: str,
    receipt_item_id: str | None = None,
    bill_member_id: str | None = None,
    assignment_id: str | None = None,
) -> None:
    if bill_ws_manager.client_count(bill_id) == 0:
        return
    payload = {"action": action}
    if receipt_item_id is not None:
        payload["receipt_item_id"] = receipt_item_id
    if bill_member_id is not None:
        payload["bill_member_id"] = bill_member_id
    if assignment_id is not None:
        payload["assignment_id"] = assignment_id
    try:
        loop = asyncio.get_event_loop()
        loop.create_task(bill_ws_manager.broadcast(bill_id, "assignment_update", payload))
    except Exception:
        logger.exception("WS delta broadcast failed for bill %s", bill_id)

app/api/routes/assignments.py :: _broadcast_full_sync
def _broadcast_full_sync(bill_id: str) -> None:
    if bill_ws_manager.client_count(bill_id) == 0:
        return
    db = SessionLocal()
    try:
        assignments = CalculationService(db).get_assignments(bill_id)
        payload = {
            "action": "full_sync",
            "assignments": [_assignment_out(a) for a in assignments],
        }
        loop = asyncio.get_event_loop()
        loop.create_task(bill_ws_manager.broadcast(bill_id, "assignment_update", payload))
    except Exception:
        logger.exception("WS full_sync broadcast failed for bill %s", bill_id)
    finally:
        db.close()

app/api/routes/assignments.py :: create_assignments
def create_assignments(
    bill_id: uuid.UUID,
    body: AssignmentBulkCreate,
    background_tasks: BackgroundTasks,
    db: Session = Depends(get_db),
    current_user: User = Depends(get_current_user),
):
    if err := _participant_error(db, str(bill_id), str(current_user.id)):
        return err

    svc = CalculationService(db)
    try:
        assignments = svc.create_assignments(
            str(bill_id),
            [a.model_dump() for a in body.assignments],
        )
    except ValueError as e:
        return error_response("BAD_REQUEST", str(e), 400)

    _maybe_schedule_payment_sms(
        background_tasks, db, bill_id, current_user, body.send_payment_notifications
    )

    results = _serialize_assignments(db, assignments)
    _schedule_added_deltas(background_tasks, str(bill_id), results)

    return success_response(data=results, message="Assignments created")

